      <span class="material-symbols-outlined text-sm">arrow_back</span>
      <span>Volver a Módulos del Curso</span>
    </a>
  </div>

  <!-- Header Banner: Structured Course and Module context -->
  <div class="border border-slate-200 p-8 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
    <div>
      <div class="flex items-center gap-2">
        <span class="text-[9px] font-black text-slate-400 bg-slate-100 border border-slate-200 px-2 py-0.5 uppercase tracking-widest rounded-none">
          Curso: {{ modulo.cursoNombre }}
        </span>
      </div>
      <h1 class="text-2xl font-black text-slate-900 mt-2 tracking-tight uppercase leading-none">
        Módulo {{ modulo.orden }}: {{ modulo.nombre }}
      </h1>
      <p class="text-slate-500 text-xs mt-1">Gestión y secuenciación de los videos de aprendizaje interactivo.</p>
    </div>
    <button 
      (click)="openCreateModal()" 
      class="flex items-center gap-2 px-4 py-2.5 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none">
      <span class="material-symbols-outlined text-sm">add</span>
      <span>Agregar Video</span>
    </button>
  </div>

  <!-- Videos Workspace -->
  <div class="border border-slate-200 bg-white rounded-none shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden">
    <!-- Filter bar -->
    <div class="p-4 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
      <div class="relative w-full max-w-xs">
        <span class="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-slate-400">
          <span class="material-symbols-outlined text-base">search</span>
        </span>
        <input 
          [(ngModel)]="searchQuery"
          (input)="applyFilter()"
          class="block w-full pl-9 pr-3 py-2 border border-slate-300 bg-white text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary text-xs rounded-none" 
          placeholder="Buscar video por título...">
      </div>
      <span class="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
        {{ filteredVideos.length }} videos en el módulo
      </span>
    </div>

    <!-- Videos List Table -->
    <div class="overflow-x-auto">
      <table class="w-full text-left border-collapse text-xs">
        <thead>
          <tr class="border-b border-slate-200 bg-slate-100/60 text-slate-700 font-bold uppercase tracking-wider text-[10px]">
            <th class="p-4 w-20">Orden</th>
            <th class="p-4">Título del Video</th>
            <th class="p-4 w-44">Enlace YouTube</th>
            <th class="p-4 w-32">Estado</th>
            <th class="p-4 text-right w-36">Acciones</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100">
          <!-- Empty state -->
          <tr *ngIf="filteredVideos.length === 0">
            <td colspan="5" class="p-12 text-center text-slate-400">
              <span class="material-symbols-outlined text-4xl mb-2 text-slate-300">smart_display</span>
              <p class="font-medium text-xs">Este módulo todavía no contiene videos registrados.</p>
            </td>
          </tr>
          <!-- Rows -->
          <tr *ngFor="let video of filteredVideos" class="hover:bg-slate-50 transition-colors">
            <!-- Orden -->
            <td class="p-4 font-black text-slate-900 text-center">
              <span class="inline-block w-6 py-0.5 bg-slate-100 border border-slate-200 text-center font-mono">
                {{ video.orden }}
              </span>
            </td>
            <!-- Título -->
            <td class="p-4 font-bold text-slate-900">
              {{ video.titulo }}
              <span class="block font-normal text-[10px] text-slate-500 mt-0.5 truncate max-w-md">{{ video.descripcion }}</span>
            </td>
            <!-- YouTube URL -->
            <td class="p-4 font-mono text-[10px] text-slate-400 truncate max-w-xs">
              <a [href]="video.youtubeUrl" target="_blank" class="text-primary hover:underline flex items-center gap-1">
                <span class="material-symbols-outlined text-xs">link</span>
                Ver en YouTube
              </a>
            </td>
            <!-- Estado -->
            <td class="p-4">
              <span [ngClass]="video.estado ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'" class="px-2.5 py-1 text-[9px] font-black uppercase tracking-wider border rounded-none">
                {{ video.estado ? 'ACTIVO' : 'INACTIVO' }}
              </span>
            </td>
            <!-- Acciones -->
            <td class="p-4 text-right">
              <div class="inline-flex gap-2">
                <button 
                  (click)="openEditModal(video)" 
                  title="Editar Video"
                  class="p-1.5 border border-slate-200 hover:border-slate-400 hover:bg-slate-50 text-slate-600 rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">edit</span>
                </button>
                <button 
                  (click)="toggleEstado(video)" 
                  [title]="video.estado ? 'Desactivar' : 'Activar'"
                  [ngClass]="video.estado ? 'border-red-200 text-red-600 hover:bg-red-50' : 'border-emerald-200 text-emerald-600 hover:bg-emerald-50'"
                  class="p-1.5 border rounded-none transition-colors">
                  <span class="material-symbols-outlined text-base block">
                    {{ video.estado ? 'block' : 'check_circle' }}
                  </span>
                </button>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>

  <!-- Create/Edit Video Modal -->
  <div *ngIf="showVideoModal" class="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4">
    <div class="w-full max-w-3xl bg-white border border-slate-200 shadow-2xl rounded-none overflow-hidden flex flex-col md:flex-row relative">

      <!-- Left Column: Form Inputs -->
      <div class="w-full md:w-3/5 p-6 border-r border-slate-200 flex flex-col justify-between">
        <div>
          <!-- Header -->
          <div class="border-b border-slate-200 pb-3 mb-4 flex items-center justify-between">
            <h3 class="text-sm font-black text-slate-900 uppercase tracking-wider">
              {{ isEditMode ? 'Editar Video' : 'Agregar Video al Módulo' }}
            </h3>
            <button (click)="closeVideoModal()" class="text-slate-400 hover:text-slate-600 md:hidden">
              <span class="material-symbols-outlined text-lg">close</span>
            </button>
          </div>

          <!-- Form Body -->
          <form [formGroup]="videoForm" class="space-y-4">
            <div *ngIf="modalErrorMsg" class="flex items-start gap-2 bg-red-50 border border-red-200 text-red-800 p-3 rounded-none text-[11px] font-semibold">
              <span class="material-symbols-outlined text-red-600 text-base">warning</span>
              <span>{{ modalErrorMsg }}</span>
            </div>

            <!-- Titulo -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Título del Video *</label>
              <input 
                formControlName="titulo" 
                type="text" 
                class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Ej. Introducción al entorno de trabajo">
              <p *ngIf="videoForm.get('titulo')?.invalid && videoForm.get('titulo')?.touched" class="text-[10px] text-red-600 mt-1">El título es obligatorio.</p>
            </div>

            <!-- Descripcion -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Descripción *</label>
              <textarea 
                formControlName="descripcion" 
                rows="2" 
                class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Indica un resumen del video..."></textarea>
              <p *ngIf="videoForm.get('descripcion')?.invalid && videoForm.get('descripcion')?.touched" class="text-[10px] text-red-600 mt-1">La descripción es obligatoria.</p>
            </div>

            <!-- Youtube URL -->
            <div>
              <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">URL de YouTube *</label>
              <input 
                formControlName="youtubeUrl" 
                type="text" 
                (input)="onUrlInput()"
                class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary"
                placeholder="Ej. https://www.youtube.com/watch?v=dQw4w9WgXcQ">
              <p *ngIf="videoForm.get('youtubeUrl')?.invalid && videoForm.get('youtubeUrl')?.touched" class="text-[10px] text-red-600 mt-1">Ingrese un enlace de YouTube válido.</p>
            </div>

            <div class="grid grid-cols-2 gap-4">
              <!-- Orden -->
              <div>
                <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Orden de Reproducción *</label>
                <input 
                  formControlName="orden" 
                  type="number" 
                  class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
                <p *ngIf="videoForm.get('orden')?.invalid && videoForm.get('orden')?.touched" class="text-[10px] text-red-600 mt-1">El orden es requerido.</p>
              </div>
              <!-- Estado -->
              <div>
                <label class="block text-[10px] font-bold text-slate-700 mb-1 uppercase tracking-widest">Estado</label>
                <select 
                  formControlName="estado" 
                  class="w-full px-3 py-2 border border-slate-300 bg-white text-slate-900 text-xs rounded-none focus:outline-none focus:ring-1 focus:ring-primary focus:border-primary">
                  <option [ngValue]="true">ACTIVO</option>
                  <option [ngValue]="false">INACTIVO</option>
                </select>
              </div>
            </div>
          </form>
        </div>

        <!-- Buttons -->
        <div class="pt-4 border-t border-slate-100 flex justify-end gap-3 mt-6">
          <button 
            type="button" 
            (click)="closeVideoModal()" 
            class="px-4 py-2 border border-slate-300 bg-white text-slate-700 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 transition-colors rounded-none">
            Cancelar
          </button>
          <button 
            type="button" 
            (click)="onSubmit()"
            [disabled]="videoForm.invalid || isFormSubmitting" 
            class="px-4 py-2 bg-slate-900 text-white font-bold text-xs uppercase tracking-widest hover:bg-slate-800 transition-colors rounded-none disabled:opacity-55">
            {{ isFormSubmitting ? 'Guardando...' : 'Guardar Video' }}
          </button>
        </div>
      </div>

      <!-- Right Column: Live YouTube Player / Thumbnail Preview -->
      <div class="w-full md:w-2/5 bg-slate-50 p-6 flex flex-col justify-between select-none">
        <div class="hidden md:flex justify-between items-center border-b border-slate-200 pb-3 mb-4 w-full">
          <span class="text-[10px] font-black text-slate-400 uppercase tracking-widest">Vista Previa de Video</span>
          <button (click)="closeVideoModal()" class="text-slate-400 hover:text-slate-600">
            <span class="material-symbols-outlined text-lg">close</span>
          </button>
        </div>

        <!-- Live Preview Content -->
        <div class="flex-grow flex flex-col justify-center items-center h-full">

          <!-- Case 1: Video ID detected -> Embed Player & Info -->
          <div *ngIf="youtubeId" class="w-full space-y-4">

            <!-- Safe iFrame Player Container -->
            <div class="aspect-video w-full border border-slate-300 bg-slate-900 relative">
              <iframe 
                *ngIf="safeEmbedUrl" 
                [src]="safeEmbedUrl" 
                class="absolute inset-0 w-full h-full"
                frameborder="0" 
                allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                allowfullscreen>
              </iframe>
            </div>

            <!-- Thumbnail view helper -->
            <div class="border border-slate-200 bg-white p-3 space-y-1.5">
              <span class="block text-[8px] font-bold text-slate-400 uppercase">Miniatura (YouTube API HQ)</span>
              <div class="aspect-video w-full overflow-hidden border border-slate-100 bg-slate-50">
                <img 
                  [src]="'https://img.youtube.com/vi/' + youtubeId + '/mqdefault.jpg'" 
                  alt="Previsualización de YouTube" 
                  class="w-full h-full object-cover">
              </div>
              <span class="block text-[9px] font-mono text-slate-400 mt-1 truncate">ID detectado: {{ youtubeId }}</span>
            </div>

          </div>

          <!-- Case 2: No video ID detected -> Empty Placeholder State -->
          <div *ngIf="!youtubeId" class="text-center p-8 border border-dashed border-slate-300 w-full aspect-video flex flex-col justify-center items-center bg-slate-100/50">
            <span class="material-symbols-outlined text-4xl text-slate-300 animate-pulse">play_circle</span>
            <h4 class="text-xs font-bold text-slate-700 uppercase mt-2">Pegue un enlace</h4>
            <p class="text-[10px] text-slate-400 mt-1 leading-normal max-w-xs">Ingrese una URL válida de YouTube para generar la vista previa e integrar el player embebido.</p>
          </div>

        </div>

        <div></div> <!-- Spacing helper -->

      </div>

    </div>
  </div>

</div>
